import jwt
import datetime
from flask import Flask, request, jsonify
from functools import wraps

app = Flask(__name__)
app.config['SECRET_KEY'] = 'your-super-secret-key-please-change-this' # Lütfen bunu güvenli bir anahtarla değiştirin!

def jwt_required(f):
    @wraps(f)
    def decorated(*args, **kwargs):
        token = None
        if 'Authorization' in request.headers:
            auth_header = request.headers['Authorization']
            parts = auth_header.split()
            if len(parts) == 2 and parts[0].lower() == 'bearer':
                token = parts[1]

        if not token:
            return jsonify({'message': 'Token eksik!'}), 401

        try:
            data = jwt.decode(token, app.config['SECRET_KEY'], algorithms=["HS256"])
            # İsterseniz token içindeki kullanıcı verisini burada g.current_user'a atayabilirsiniz.
            # g.current_user = data['user_id']
        except jwt.ExpiredSignatureError:
            return jsonify({'message': 'Token süresi dolmuştur!'}), 401
        except jwt.InvalidTokenError:
            return jsonify({'message': 'Geçersiz token!'}), 401

        return f(*args, **kwargs)
    return decorated

@app.route('/login', methods=['POST'])
def login():
    auth = request.json
    if not auth or not auth.get('username') or not auth.get('password'):
        return jsonify({'message': 'Giriş bilgileri eksik'}), 401

    # Gerçek bir uygulamada, kullanıcı adı ve şifre veritabanından doğrulanmalıdır.
    if auth.get('username') == 'testuser' and auth.get('password') == 'testpassword':
        token = jwt.encode(
            {
                'user_id': auth.get('username'),
                'exp': datetime.datetime.utcnow() + datetime.timedelta(minutes=330) # Token 30 dakika sonra sona erer
            },
            app.config['SECRET_KEY'],
            algorithm="HS256"
        )
        return jsonify({'token': token})

    return jsonify({'message': 'Kullanıcı adı veya şifre yanlış'}), 401

@app.route('/protected', methods=['GET'])
@jwt_required
def protected_route():
    return jsonify({'message': 'Bu korumalı bir rotadır! Geçerli bir tokena sahipsiniz.'})

@app.route('/unprotected', methods=['GET'])
def unprotected_route():
    return jsonify({'message': 'Bu korumalı olmayan bir rotadır.'})

if __name__ == '__main__':
    app.run(debug=True)
